import{bQ as e,aL as r,u as a,G as d}from"./chunks/framework.D06dwy5q.js";const b=JSON.parse('{"title":"容器和编排","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/11-容器和编排.md","filePath":"00.互联网与架构基础/11-容器和编排.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/11-容器和编排.md"};function n(i,t,h,p,l,s){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="容器和编排" tabindex="-1">容器和编排 <a class="header-anchor" href="#容器和编排" aria-label="Permalink to &quot;容器和编排&quot;">​</a></h1><p>以前部署应用，经常要登录服务器，安装运行时，复制代码或二进制，改配置，再启动进程。机器少的时候还能管住，机器多了以后，环境差异、依赖冲突、发布回滚和扩容都会变麻烦。</p><p>容器把应用和依赖打包成镜像，让同一份东西在不同机器上以接近一致的方式运行。编排系统再负责把很多容器放到集群里运行，处理调度、重启、服务发现、扩缩容和滚动发布。</p><h2 id="一、手工部署的问题" tabindex="-1">一、手工部署的问题 <a class="header-anchor" href="#一、手工部署的问题" aria-label="Permalink to &quot;一、手工部署的问题&quot;">​</a></h2><p>手工部署常见问题是环境漂移。同一个应用在测试机能跑，到了生产机因为系统库版本、环境变量、目录权限、运行用户不一致而失败。</p><p>常见问题：</p><table tabindex="0"><thead><tr><th>问题</th><th>表现</th></tr></thead><tbody><tr><td>依赖不一致</td><td>缺少动态库、Python 包版本不同、JDK 版本不同</td></tr><tr><td>发布不可重复</td><td>同样步骤换个人执行，结果可能不一样</td></tr><tr><td>回滚困难</td><td>不知道上一版文件和配置是否完整</td></tr><tr><td>扩容慢</td><td>新机器要重新装环境</td></tr><tr><td>进程管理分散</td><td>启停脚本、日志路径、运行用户不统一</td></tr></tbody></table><p>虚拟机能隔离整套操作系统，但启动和分发成本较高。容器选择隔离进程运行环境，把应用依赖收进镜像里。</p><h2 id="二、镜像和容器" tabindex="-1">二、镜像和容器 <a class="header-anchor" href="#二、镜像和容器" aria-label="Permalink to &quot;二、镜像和容器&quot;">​</a></h2><p>镜像是静态制品，容器是镜像运行起来后的进程环境。</p><table tabindex="0"><thead><tr><th>对象</th><th>含义</th></tr></thead><tbody><tr><td>镜像</td><td>打包好的应用、依赖、启动命令和文件系统</td></tr><tr><td>容器</td><td>镜像运行后的实例</td></tr><tr><td>镜像仓库</td><td>保存和分发镜像的地方，例如 Harbor</td></tr><tr><td>运行时</td><td>创建和管理容器的组件，例如 containerd</td></tr></tbody></table><p>镜像可以理解成应用发布包。构建镜像后推到仓库，服务器拉取同一个镜像运行，发布内容就不再依赖人工复制文件。</p><p>容器和虚拟机的隔离方式不同。容器里的进程仍然共享宿主机内核，通过 namespace、cgroup 等机制隔离进程、网络、文件系统和资源限制。</p><h2 id="三、docker-的位置" tabindex="-1">三、Docker 的位置 <a class="header-anchor" href="#三、docker-的位置" aria-label="Permalink to &quot;三、Docker 的位置&quot;">​</a></h2><p>Docker 把镜像构建、镜像管理、容器运行、网络和卷这些能力做成了容易使用的工具。很多人第一次接触容器都是从 Docker 开始。</p><p>后来 Kubernetes 默认运行时逐步转向 containerd 这类更底层的容器运行时。Docker 仍然常用于本地构建、开发调试和理解容器概念；在 Kubernetes 节点上，被 kubelet 调用的通常是符合 CRI 接口的运行时。</p><p>关系大致是：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20Image%5B%22OCI%20%E9%95%9C%E5%83%8F%22%5D%0A%20%20Docker%5B%22Docker%20%E5%B7%A5%E5%85%B7%22%5D%0A%20%20Registry%5B%22%E9%95%9C%E5%83%8F%E4%BB%93%E5%BA%93%22%5D%0A%20%20Kubelet%5B%22kubelet%22%5D%0A%20%20Runtime%5B%22containerd%20%2F%20CRI-O%22%5D%0A%20%20Container%5B%22%E5%AE%B9%E5%99%A8%E8%BF%9B%E7%A8%8B%22%5D%0A%0A%20%20Docker%20--%3E%20Image%0A%20%20Image%20--%3E%20Registry%0A%20%20Kubelet%20--%3E%20Runtime%0A%20%20Runtime%20--%3E%20Container%0A%20%20Registry%20--%3E%20Runtime%0A"></div><p>OCI 镜像规范让不同工具构建出来的镜像能被不同运行时识别。镜像仓库让构建和运行解耦。</p><h2 id="四、kubernetes-为什么出现" tabindex="-1">四、Kubernetes 为什么出现 <a class="header-anchor" href="#四、kubernetes-为什么出现" aria-label="Permalink to &quot;四、Kubernetes 为什么出现&quot;">​</a></h2><p>单机 Docker 能运行容器，但生产环境通常有很多机器、很多服务和很多副本。容器放在哪台机器，挂了谁来拉起，服务之间怎么互相找到，配置和密钥怎么注入，发布时怎么逐步替换，这些都需要系统处理。</p><p>Kubernetes 就是这类编排系统。它把“想要几个副本、暴露什么服务、挂载什么配置、使用什么镜像”写成资源对象，再由控制器不断把集群调整到期望状态。</p><p>Google 早期内部有大规模集群管理系统 Borg。容器生态成熟后，Kubernetes 把声明式 API、控制器、调度、服务发现和滚动发布这些能力整理成开源系统。</p><h2 id="五、常见对象" tabindex="-1">五、常见对象 <a class="header-anchor" href="#五、常见对象" aria-label="Permalink to &quot;五、常见对象&quot;">​</a></h2><p>Kubernetes 里常见对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>作用</th></tr></thead><tbody><tr><td>Pod</td><td>最小运行单元，里面放一个或多个容器</td></tr><tr><td>Deployment</td><td>管理无状态应用副本和滚动发布</td></tr><tr><td>Service</td><td>给一组 Pod 提供稳定访问入口</td></tr><tr><td>ConfigMap</td><td>保存非敏感配置</td></tr><tr><td>Secret</td><td>保存密码、证书、Token 等敏感配置</td></tr><tr><td>Ingress / Gateway</td><td>暴露 HTTP/HTTPS 入口</td></tr><tr><td>PVC</td><td>申请持久化存储</td></tr></tbody></table><p>这些对象把原来散在脚本、配置文件和人工操作里的步骤，变成了集群 API 里的资源。运维不再只看某个进程是否存在，还要看期望状态、控制器动作、Pod 事件和调度结果。</p><h2 id="六、容器化也会带来新问题" tabindex="-1">六、容器化也会带来新问题 <a class="header-anchor" href="#六、容器化也会带来新问题" aria-label="Permalink to &quot;六、容器化也会带来新问题&quot;">​</a></h2><p>容器解决了打包和运行一致性，也带来新的排查对象。镜像要维护安全更新，容器日志要采集，运行时要监控，网络和存储要重新理解，Kubernetes 集群本身也要升级、备份和排错。</p><p>容器化以后，一个接口 502 可能和应用进程有关，也可能和 Pod 探针、Service selector、Ingress 路由、镜像拉取、节点资源、CNI 网络有关。对象变多了，但每个对象都有明确的状态和事件可查。</p><p>容器和编排把应用部署从“在某台机器上跑一个进程”，变成“在集群里维持一组期望状态”。</p>',31)])])}const u=e(o,[["render",n]]);export{b as __pageData,u as default};
